import { useEffect, useState } from 'react';
import { Mail, Github, Linkedin } from 'lucide-react';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

const phrasesEn = ['Cybersecurity Enthusiast','AI & Gen AI Practitioner','Web Developer','Network Enthusiast','MIS Student'];
const phrasesAr = ['متحمس للأمن السيبراني','ممارس للذكاء الاصطناعي','مطور ويب','متحمس للشبكات','طالب نظم معلومات'];

export default function Hero() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const phrases = lang === 'ar' ? phrasesAr : phrasesEn;

  const [text, setText] = useState('');
  const [pi, setPi] = useState(0);
  const [ci, setCi] = useState(0);
  const [del, setDel] = useState(false);

  useEffect(() => { setText(''); setCi(0); setPi(0); setDel(false); }, [lang]);

  useEffect(() => {
    const phrase = phrases[pi];
    const timer = setTimeout(() => {
      if (!del) {
        setText(phrase.slice(0, ci + 1));
        if (ci + 1 === phrase.length) { setTimeout(() => setDel(true), 1600); return; }
        setCi(c => c + 1);
      } else {
        setText(phrase.slice(0, ci - 1));
        if (ci - 1 === 0) { setDel(false); setPi(p => (p + 1) % phrases.length); setCi(0); return; }
        setCi(c => c - 1);
      }
    }, del ? 45 : 90);
    return () => clearTimeout(timer);
  }, [ci, pi, del, phrases]);

  const bg      = dark ? 'bg-[#0f0f14]'   : 'bg-parchment';
  const textBase = dark ? 'text-white'      : 'text-ink';
  const textMuted = dark ? 'text-white/50'  : 'text-muted2';
  const borderBtn = dark
    ? 'border-white/20 text-white/70 hover:border-amber hover:text-amber'
    : 'border-ink/20 text-ink2 hover:border-amber hover:text-amber';
  const socBtn = dark
    ? 'border-white/15 text-white/50 hover:border-amber hover:text-amber'
    : 'border-ink/12 text-muted2 hover:border-amber hover:text-amber';
  const badgeBg = dark ? 'bg-[#1a1a28] border border-white/10' : 'bg-white/90 backdrop-blur-sm';

  return (
    <section id="hero"
      className={`min-h-screen ${bg} grid md:grid-cols-2 items-center gap-8 px-[5%] relative overflow-hidden transition-colors duration-300`}>

      {/* Background blobs */}
      <div className="blob-hero w-[520px] h-[520px] bg-amber opacity-10 top-[-80px] right-[-100px]" />
      <div className="blob-hero-2 w-[240px] h-[240px] bg-teal opacity-[0.07] bottom-[-30px] left-[35%]" />

      {/* ── LEFT ── */}
      <div className="relative z-10 pt-24 pb-10 md:pb-0 md:pt-0">

        <p className={`text-lg ${textMuted} mb-1`}>{tr.hiIm}</p>

        <h1 className="font-serif-display leading-[1.02] tracking-tight mb-0">
          <span className={`block text-5xl md:text-7xl ${textBase}`}>Kareem Basem</span>
          <em className="block text-5xl md:text-7xl text-amber not-italic font-serif-display">Fathi.</em>
        </h1>

        {/* Typewriter */}
        <div className="flex items-center gap-2 mt-5 text-sm font-medium">
          <span className="text-amber font-bold">→</span>
          <span className={`font-semibold ${textBase}`}>{text}</span>
          <span className="text-amber animate-[ping2_1s_step-end_infinite]">|</span>
        </div>

        <p className={`mt-4 text-[0.95rem] leading-[1.8] ${textMuted} max-w-[440px]`}>
          {tr.heroDesc}
        </p>

        <div className="flex gap-3 flex-wrap mt-7">
          <a href="#projects"
            className="px-6 py-3 bg-amber text-white font-semibold text-sm rounded-full transition-all hover:bg-amber2 hover:-translate-y-1 hover:shadow-[0_8px_24px_rgba(240,165,0,.3)]">
            {tr.viewWork}
          </a>
          <a href="#contact"
            className={`px-6 py-3 border-[1.5px] font-semibold text-sm rounded-full transition-all hover:-translate-y-1 ${borderBtn}`}>
            {tr.getInTouch}
          </a>
        </div>

        {/* Social links with Lucide icons */}
        <div className="flex items-center gap-3 mt-7">
          <span className={`text-xs uppercase tracking-wider font-medium ${textMuted}`}>{tr.findMe}</span>
          <a href="https://www.linkedin.com/in/karem-basem" target="_blank" rel="noreferrer"
            className={`w-9 h-9 rounded-full border-[1.5px] flex items-center justify-center transition-all hover:-translate-y-0.5 ${socBtn}`}>
            <Linkedin size={15} />
          </a>
          <a href="https://github.com/Kareem-Basem" target="_blank" rel="noreferrer"
            className={`w-9 h-9 rounded-full border-[1.5px] flex items-center justify-center transition-all hover:-translate-y-0.5 ${socBtn}`}>
            <Github size={15} />
          </a>
          <a href="mailto:karemalwy1@gmail.com"
            className={`w-9 h-9 rounded-full border-[1.5px] flex items-center justify-center transition-all hover:-translate-y-0.5 ${socBtn}`}>
            <Mail size={15} />
          </a>
        </div>
      </div>

      {/* ── RIGHT — Real Photo ── */}
      <div className="hidden md:flex flex-col items-center gap-5 relative z-10">
        <div className="relative w-[310px] h-[310px] float">

          {/* Animated blob background */}
          <div className="blob-avatar absolute inset-0 bg-gradient-to-br from-amber to-[#ffd166]" />

          {/* Photo circle */}
          <div className="absolute inset-[18px] rounded-full overflow-hidden"
            style={{ boxShadow: 'inset 0 4px 20px rgba(26,26,46,.12)' }}>
            <img
              src={process.env.PUBLIC_URL + '/assets/photo/kareem.jpg'}
              alt="Kareem Basem Fathi"
              className="w-full h-full object-cover"
              style={{ objectPosition: 'center top' }}
            />
          </div>

          {/* Badge — Open to Work */}
          <div className={`absolute top-3 -right-6 ${badgeBg} rounded-2xl px-3 py-2 shadow-lg flex items-center gap-2`}>
            <span className="w-2 h-2 rounded-full bg-green-500 ping2 block flex-shrink-0" />
            <div>
              <div className={`text-[0.78rem] font-semibold ${textBase}`}>{tr.openToWork}</div>
              <div className="text-[0.65rem] text-muted">{tr.availableNow}</div>
            </div>
          </div>

          {/* Badge — Certs count */}
          <div className={`absolute bottom-6 -left-8 ${badgeBg} rounded-2xl px-3 py-2 shadow-lg flex items-center gap-2`}>
            <span className="font-serif-display text-2xl italic text-teal font-bold">20+</span>
            <div className={`text-[0.65rem] leading-tight ${textMuted}`}>
              {tr.certifications}<br/>{tr.earned}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
